#include "markforge/diagnostics.h"
const char*mf_diag_severity_name(mf_diag_severity_t s){ switch(s){case MF_DIAG_NOTE:return "note";case MF_DIAG_WARNING:return "warning";case MF_DIAG_ERROR:return "error";default:return "diagnostic";} }
void mf_diag_bag_init(mf_diagnostic_bag_t*bag){ if(bag) memset(bag,0,sizeof(*bag)); }
void mf_diag_bag_destroy(mf_diagnostic_bag_t*bag){ if(bag){free(bag->items);memset(bag,0,sizeof(*bag));} }
static mf_result_t diag_grow(mf_diagnostic_bag_t*bag){ mf_diagnostic_t*p; size_t nc=bag->capacity?bag->capacity*2U:8U; p=(mf_diagnostic_t*)realloc(bag->items,nc*sizeof(*p)); if(!p) return MF_ERROR_NOMEM; bag->items=p; bag->capacity=nc; return MF_OK; }
mf_result_t mf_diag_add(mf_diagnostic_bag_t*bag,mf_diag_severity_t severity,int code,mf_source_region_t region,const char*message,const char*suggestion){ mf_diagnostic_t*d; if(!bag||!message) return MF_ERROR_INVALID; if(bag->count==bag->capacity && diag_grow(bag)!=MF_OK) return MF_ERROR_NOMEM; d=&bag->items[bag->count++]; memset(d,0,sizeof(*d)); d->code=code; d->severity=severity; d->region=region; snprintf(d->message,sizeof(d->message),"%s",message); if(suggestion) snprintf(d->suggestion,sizeof(d->suggestion),"%s",suggestion); return MF_OK; }
size_t mf_diag_count(const mf_diagnostic_bag_t*bag){ return bag?bag->count:0U; }
void mf_diag_print(const mf_diagnostic_bag_t*bag,FILE*out,int color){ size_t i; if(!bag) return; if(!out) out=stderr; for(i=0U;i<bag->count;i++){ const mf_diagnostic_t*d=&bag->items[i]; const char*c=color?(d->severity==MF_DIAG_ERROR?"\033[31m":(d->severity==MF_DIAG_WARNING?"\033[33m":"\033[36m")):""; const char*r=color?"\033[0m":""; fprintf(out,"%s%s:%lu:%lu: %s MF%04d: %s%s\n",c,d->region.file?d->region.file:"<input>",(unsigned long)d->region.line,(unsigned long)d->region.column,mf_diag_severity_name(d->severity),d->code,d->message,r); if(d->region.length) fprintf(out,"  highlight: column %lu length %lu\n",(unsigned long)d->region.column,(unsigned long)d->region.length); if(d->suggestion[0]) fprintf(out,"  suggestion: %s\n",d->suggestion); } }
